const products = [
  { id: 1, name: "خاتم ذهبي عصري", price: 120, image: "data:image/jpeg;base64," },
  { id: 2, name: "سلسلة أنيقة", price: 180, image: "data:image/jpeg;base64," },
  { id: 3, name: "سوار راقي", price: 150, image: "data:image/jpeg;base64," },
  { id: 4, name: "قلادة مميزة", price: 200, image: "data:image/jpeg;base64," },
  { id: 5, name: "طقم خفيف", price: 160, image: "data:image/jpeg;base64," },
  { id: 6, name: "خاتم فضة", price: 140, image: "data:image/jpeg;base64," },
  { id: 7, name: "سلسلة دلاية", price: 170, image: "data:image/jpeg;base64," },
  { id: 8, name: "طقم وردي", price: 190, image: "data:image/jpeg;base64," },
  { id: 9, name: "اساور لامعة", price: 175, image: "data:image/jpeg;base64," },
  { id: 10, name: "أكسسوار فخم", price: 220, image: "data:image/jpeg;base64," },
  { id: 11, name: "سلسلة ناعمة", price: 160, image: "data:image/jpeg;base64," },
  { id: 12, name: "طقم كلاسيكي", price: 210, image: "data:image/jpeg;base64," }
];

const whatsappNumber = "201151620711";
const selectedProducts = new Set();

// Images are embedded in the `products` array as data URLs.
// Keep those in-file data URLs and do not overwrite them with external file paths.

function getProductImageLink(product) {
  if (!product || !product.image) return "";
  // If the image is already a data URL embed, return it directly.
  if (typeof product.image === 'string' && product.image.startsWith('data:')) {
    return product.image;
  }
  // Otherwise treat it as a relative path and resolve to an absolute URL when not served from file://
  if (typeof product.image === 'string') {
    if (window.location.protocol === 'file:') return product.image;
    try {
      return new URL(product.image, window.location.href).href;
    } catch (e) {
      return product.image;
    }
  }
  return '';
}

function displayProducts() {
  const productGrid = document.getElementById("product-grid");
  productGrid.innerHTML = "";

  products.forEach(product => {
    const selected = selectedProducts.has(product.id);
    const imageSrc = getProductImageLink(product) || product.image;
    productGrid.innerHTML += `
      <div class="card ${selected ? "selected" : ""}" data-product-id="${product.id}">
        <img src="${imageSrc}" alt="${product.name}">
        <div class="product-info">
          <h3>${product.name}</h3>
          <label class="product-select">
            <input type="checkbox" ${selected ? "checked" : ""} onchange="toggleProduct(${product.id}, this.checked)">
            اختر المنتج
          </label>
        </div>
      </div>
    `;
  });
}

function toggleProduct(productId, checked) {
  if (checked) {
    selectedProducts.add(productId);
  } else {
    selectedProducts.delete(productId);
  }
  displayProducts();
}

function getSelectedItems() {
  return products.filter(product => selectedProducts.has(product.id));
}

function orderSelected() {
  const selectedItems = getSelectedItems();
  const customText = document.getElementById("custom-request").value.trim();

  if (selectedItems.length === 0 && !customText) {
    alert("اختر منتجا أو اكتب طلبا مخصصا ثم اضغط طلب.");
    return;
  }

  let message = "مرحبا أود طلب المنتجات التالية:\n";

  if (selectedItems.length > 0) {
    selectedItems.forEach(item => {
      message += `- ${item.name}\n`;
    });
  }

  if (customText) {
    message += `\nطلب مخصص:\n${customText}`;
  }

  openWhatsApp(message);
}

function orderCustom() {
  const customText = document.getElementById("custom-request").value.trim();
  if (!customText) {
    alert("اكتب طلبك المخصص في المربع أولا.");
    return;
  }

  const message = `مرحبا أود طلب مخصص:\n${customText}`;
  openWhatsApp(message);
}

function openWhatsApp(message) {
  const url = `https://wa.me/${whatsappNumber}?text=${encodeURIComponent(message)}`;
  window.open(url, "_blank");
}

window.addEventListener("load", () => {
  displayProducts();
  document.getElementById("order-selected").addEventListener("click", orderSelected);
  document.getElementById("custom-order").addEventListener("click", orderCustom);
  const openCustomBtn = document.getElementById("open-custom");
  if (openCustomBtn) {
    openCustomBtn.addEventListener("click", () => {
      const panel = document.querySelector('.order-panel');
      if (panel) {
        panel.scrollIntoView({ behavior: 'smooth', block: 'center' });
      }
      const textarea = document.getElementById('custom-request');
      if (textarea) textarea.focus();
    });
  }

  const names = [
    "اسوره اية الكرسي اسود",
    "اسوره اية الكرسي فضي",
    "اسوره lacoste اسود",
    "طقم سلسله و انسيال",
    "خاتم استانلس",
    "خاتم استانلس",
    "اسوره اية الكرسي ذهبي",
    "خاتم استانلس",
    "اسوره lacoste فضي",
    "سلسله ب الاسم",
    "سلسله ب الاسم",
    "خاتم"
  ];

  products.forEach((p, i) => {
    if (names[i]) p.name = names[i];
  });

  displayProducts();

  const grid = document.getElementById('product-grid');
  const modal = document.getElementById('product-modal');
  const modalImg = modal.querySelector('.modal-img');
  const modalCaption = modal.querySelector('.modal-caption');
  const modalClose = modal.querySelector('.modal-close');

  function openProductModal(product) {
    modalImg.src = getProductImageLink(product) || product.image;
    modalImg.alt = product.name;
    modalCaption.textContent = product.name;
    modal.setAttribute('aria-hidden', 'false');
  }

  function closeProductModal() {
    modal.setAttribute('aria-hidden', 'true');
    modalImg.src = '';
    modalImg.alt = '';
    modalCaption.textContent = '';
  }

  if (grid) {
    grid.addEventListener('click', (e) => {
      const img = e.target.closest('img');
      if (!img) return;
      const productId = Number(img.closest('.card')?.dataset.productId);
      if (productId) {
        const product = products.find(p => p.id === productId);
        if (product) openProductModal(product);
      }
    });
  }

  if (modalClose) modalClose.addEventListener('click', closeProductModal);
  if (modal) {
    modal.addEventListener('click', (e) => {
      if (e.target === modal) closeProductModal();
    });
  }
  document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape') closeProductModal();
  });
});
